static inline void heartwall_kernel_impl(
	__global fp *d_frame,
	__global int *d_Row,
	__global int *d_Col,
	__global int *d_tRowLoc,
	__global int *d_tColLoc,
	__global fp *d_T,
	__global fp *d_in2,
	__global fp *d_conv,
	__global fp *d_in2_pad_cumv,
	__global fp *d_in2_pad_cumv_sel,
	__global fp *d_in2_sub_cumh,
	__global fp *d_in2_sub_cumh_sel,
	__global fp *d_in2_sub2,
	__global fp *d_in2_sqr,
	__global fp *d_in2_sqr_sub2,
	__global fp *d_in_sqr,
	__global fp *d_tMask,
	__global fp *d_mask_conv,
	int frame_no,
	params_common d_common)
{
	int rot_row;
	int rot_col;
	int in2_rowlow;
	int in2_collow;
	int ic;
	int jc;
	int jp1;
	int ja1, ja2;
	int ip1;
	int ia1, ia2;
	int ja, jb;
	int ia, ib;
	float s;
	int i;
	int j;
	int row;
	int col;
	int ori_row;
	int ori_col;
	int position;
	float sum;
	int pos_ori;
	float temp;
	float temp2;
	int location;
	int cent;
	int tMask_row;
	int tMask_col;
	float largest_value_current = 0.0f;
	float largest_value = 0.0f;
	int largest_coordinate_current = 0;
	int largest_coordinate = 0;
	float fin_max_val = 0.0f;
	int fin_max_coo = 0;
	int largest_row;
	int largest_col;
	int offset_row;
	int offset_col;
	__local float in_partial_sum[51];
	__local float in_sqr_partial_sum[51];
	__local float in_final_sum;
	__local float in_sqr_final_sum;
	float mean;
	float mean_sqr;
	float variance;
	float deviation;
	__local float denomT;
	__local float par_max_val[131];
	__local int par_max_coo[131];
	int pointer;
	__local float d_in_mod_temp[2601];
	int ori_pointer;
	int loc_pointer;

	const int bx = get_group_id(0);
	const int tx = get_local_id(0);
	const int stride = get_local_size(0);
	int ei_new;

	__global fp *d_in = d_T + bx * d_common.in_elem;
	__global fp *d_in2_p = d_in2 + bx * d_common.in2_elem;
	__global fp *d_conv_p = d_conv + bx * d_common.conv_elem;
	__global fp *d_in2_pad_cumv_p = d_in2_pad_cumv + bx * d_common.in2_pad_cumv_elem;
	__global fp *d_in2_pad_cumv_sel_p = d_in2_pad_cumv_sel + bx * d_common.in2_pad_cumv_sel_elem;
	__global fp *d_in2_sub_cumh_p = d_in2_sub_cumh + bx * d_common.in2_sub_cumh_elem;
	__global fp *d_in2_sub_cumh_sel_p = d_in2_sub_cumh_sel + bx * d_common.in2_sub_cumh_sel_elem;
	__global fp *d_in2_sub2_p = d_in2_sub2 + bx * d_common.in2_sub2_elem;
	__global fp *d_in2_sqr_p = d_in2_sqr + bx * d_common.in2_sqr_elem;
	__global fp *d_in2_sqr_sub2_p = d_in2_sqr_sub2 + bx * d_common.in2_sqr_sub2_elem;
	__global fp *d_in_sqr_p = d_in_sqr + bx * d_common.in_sqr_elem;
	__global fp *d_tMask_p = d_tMask + bx * d_common.tMask_elem;
	__global fp *d_mask_conv_p = d_mask_conv + bx * d_common.mask_conv_elem;

	if(frame_no == 0){

		ei_new = tx;
		if(ei_new == 0){
			pointer = bx * d_common.no_frames + frame_no;
			d_tRowLoc[pointer] = d_Row[bx];
			d_tColLoc[pointer] = d_Col[bx];
		}

		ei_new = tx;
		while(ei_new < d_common.in_elem){

			row = (ei_new + 1) % d_common.in_rows - 1;
			col = (ei_new + 1) / d_common.in_rows + 1 - 1;
			if((ei_new + 1) % d_common.in_rows == 0){
				row = d_common.in_rows - 1;
				col = col - 1;
			}

			ori_row = d_Row[bx] - 25 + row - 1;
			ori_col = d_Col[bx] - 25 + col - 1;
			ori_pointer = ori_col * d_common.frame_rows + ori_row;

			d_in[col * d_common.in_rows + row] = d_frame[ori_pointer];

			ei_new = ei_new + stride;
		}
	}

	if(frame_no != 0){

		in2_rowlow = d_Row[bx] - d_common.sSize;
		in2_collow = d_Col[bx] - d_common.sSize;

		ei_new = tx;
		while(ei_new < d_common.in2_elem){

			row = (ei_new + 1) % d_common.in2_rows - 1;
			col = (ei_new + 1) / d_common.in2_rows + 1 - 1;
			if((ei_new + 1) % d_common.in2_rows == 0){
				row = d_common.in2_rows - 1;
				col = col - 1;
			}

			ori_row = row + in2_rowlow - 1;
			ori_col = col + in2_collow - 1;
			d_in2_p[ei_new] = d_frame[ori_col * d_common.frame_rows + ori_row];

			ei_new = ei_new + stride;
		}

		barrier(CLK_LOCAL_MEM_FENCE | CLK_GLOBAL_MEM_FENCE);

		ei_new = tx;
		while(ei_new < d_common.in_elem){

			row = (ei_new + 1) % d_common.in_rows - 1;
			col = (ei_new + 1) / d_common.in_rows + 1 - 1;
			if((ei_new + 1) % d_common.in_rows == 0){
				row = d_common.in_rows - 1;
				col = col - 1;
			}

			rot_row = (d_common.in_rows - 1) - row;
			rot_col = (d_common.in_rows - 1) - col;
			d_in_mod_temp[ei_new] = d_in[rot_col * d_common.in_rows + rot_row];

			ei_new = ei_new + stride;
		}

		barrier(CLK_LOCAL_MEM_FENCE | CLK_GLOBAL_MEM_FENCE);

		ei_new = tx;
		while(ei_new < d_common.conv_elem){

			ic = (ei_new + 1) % d_common.conv_rows;
			jc = (ei_new + 1) / d_common.conv_rows + 1;
			if((ei_new + 1) % d_common.conv_rows == 0){
				ic = d_common.conv_rows;
				jc = jc - 1;
			}

			j = jc + d_common.joffset;
			jp1 = j + 1;
			if(d_common.in2_cols < jp1){
				ja1 = jp1 - d_common.in2_cols;
			}
			else{
				ja1 = 1;
			}
			if(d_common.in_cols < j){
				ja2 = d_common.in_cols;
			}
			else{
				ja2 = j;
			}

			i = ic + d_common.ioffset;
			ip1 = i + 1;

			if(d_common.in2_rows < ip1){
				ia1 = ip1 - d_common.in2_rows;
			}
			else{
				ia1 = 1;
			}
			if(d_common.in_rows < i){
				ia2 = d_common.in_rows;
			}
			else{
				ia2 = i;
			}

			s = 0.0f;

			for(ja = ja1; ja <= ja2; ja++){
				jb = jp1 - ja;
				for(ia = ia1; ia <= ia2; ia++){
					ib = ip1 - ia;
					s = s + d_in_mod_temp[d_common.in_rows * (ja - 1) + ia - 1] * d_in2_p[d_common.in2_rows * (jb - 1) + ib - 1];
				}
			}

			d_conv_p[ei_new] = s;

			ei_new = ei_new + stride;
		}

		barrier(CLK_LOCAL_MEM_FENCE | CLK_GLOBAL_MEM_FENCE);

