__kernel void hotspotOpt1(__global const float *p,
                          __global const float *tIn,
                          __global float *tOut,
                          const float sdc,
                          const int nx,
                          const int ny,
                          const int nz,
                          const float ce,
                          const float cw,
                          const float cn,
                          const float cs,
                          const float ct,
                          const float cb,
                          const float cc)
{
    const float amb_temp = 80.0f;

    const int i = (int)get_global_id(0);
    const int j = (int)get_global_id(1);

    if (i >= nx || j >= ny) return;

    int c = i + j * nx;
    const int xy = nx * ny;

    int W = (i == 0)      ? c : c - 1;
    int E = (i == nx - 1) ? c : c + 1;
    int N = (j == 0)      ? c : c - nx;
    int S = (j == ny - 1) ? c : c + nx;

    for (int k = 0; k < nz; ++k) {
        const int B = (k == 0)      ? c : c - xy;
        const int T = (k == nz - 1) ? c : c + xy;

        tOut[c] = cc * tIn[c]
                + cw * tIn[W]
                + ce * tIn[E]
                + cs * tIn[S]
                + cn * tIn[N]
                + cb * tIn[B]
