__kernel void
lud_perimeter(__global float *m,
              __local float *dia,
              __local float *peri_row,
              __local float *peri_col,
              int matrix_dim,
              int offset)
{
    int tx = (int)get_local_id(0);
    int bx = (int)get_group_id(0);
    int i, j, array_offset;
    int idx;

    if (tx < BLOCK_SIZE) {
        idx = tx;

        array_offset = offset * matrix_dim + offset;
        for (i = 0; i < BLOCK_SIZE / 2; i++) {
            dia[IDX(i, idx)] = m[array_offset + idx];
            array_offset += matrix_dim;
        }

        array_offset = offset * matrix_dim + offset;
        for (i = 0; i < BLOCK_SIZE; i++) {
            peri_row[IDX(i, idx)] = m[array_offset + (bx + 1) * BLOCK_SIZE + idx];
            array_offset += matrix_dim;
        }
    } else {
        idx = tx - BLOCK_SIZE;

        array_offset = (offset + BLOCK_SIZE / 2) * matrix_dim + offset;
        for (i = BLOCK_SIZE / 2; i < BLOCK_SIZE; i++) {
            dia[IDX(i, idx)] = m[array_offset + idx];
            array_offset += matrix_dim;
        }

        array_offset = (offset + (bx + 1) * BLOCK_SIZE) * matrix_dim + offset;
        for (i = 0; i < BLOCK_SIZE; i++) {
            peri_col[IDX(i, idx)] = m[array_offset + idx];
            array_offset += matrix_dim;
        }
    }

    barrier(CLK_LOCAL_MEM_FENCE);

    if (tx < BLOCK_SIZE) {
        idx = tx;
        for (i = 1; i < BLOCK_SIZE; i++) {
            for (j = 0; j < i; j++)
                peri_row[IDX(i, idx)] -= dia[IDX(i, j)] * peri_row[IDX(j, idx)];
        }
    } else {
        idx = tx - BLOCK_SIZE;
        for (i = 0; i < BLOCK_SIZE; i++) {
            for (j = 0; j < i; j++)
                peri_col[IDX(idx, i)] -= peri_col[IDX(idx, j)] * dia[IDX(j, i)];
            peri_col[IDX(idx, i)] /= dia[IDX(i, i)];
        }
    }

    barrier(CLK_LOCAL_MEM_FENCE);

    if (tx < BLOCK_SIZE) {
        idx = tx;
        array_offset = (offset + 1) * matrix_dim + offset;
        for (i = 1; i < BLOCK_SIZE; i++) {
            m[array_offset + (bx + 1) * BLOCK_SIZE + idx] = peri_row[IDX(i, idx)];
            array_offset += matrix_dim;
        }
    } else {
        idx = tx - BLOCK_SIZE;
        array_offset = (offset + (bx + 1) * BLOCK_SIZE) * matrix_dim + offset;
        for (i = 0; i < BLOCK_SIZE; i++) {
            m[array_offset + idx] = peri_col[IDX(i, idx)];
            array_offset += matrix_dim;
        }
    }
}

__kernel void
lud_internal(__global float *m,
             __local float *peri_row,
             __local float *peri_col,
             int matrix_dim,
             int offset)
{
    int tx = (int)get_local_id(0);
    int ty = (int)get_local_id(1);
    int bx = (int)get_group_id(0);
    int by = (int)get_group_id(1);
    int i;
    float sum;

    int global_row_id = offset + (by + 1) * BLOCK_SIZE;
    int global_col_id = offset + (bx + 1) * BLOCK_SIZE;

    peri_row[IDX(ty, tx)] = m[(offset + ty) * matrix_dim + global_col_id + tx];
    peri_col[IDX(ty, tx)] = m[(global_row_id + ty) * matrix_dim + offset + tx];

    barrier(CLK_LOCAL_MEM_FENCE);

    sum = 0.0f;
    for (i = 0; i < BLOCK_SIZE; i++)
        sum += peri_col[IDX(ty, i)] * peri_row[IDX(i, tx)];

    m[(global_row_id + ty) * matrix_dim + global_col_id + tx] -= sum;
}

