    rcn24 = k24*pow(Ca,2.0f)*Ca2CaM - k42*Ca4CaM;

    B = Btot - CaMB - Ca2CaMB - Ca4CaMB;
    rcn02B = k02B*pow(Ca,2.0f)*CaMB - k20B*Ca2CaMB;
    rcn24B = k24B*pow(Ca,2.0f)*Ca2CaMB - k42B*Ca4CaMB;
    rcn0B = k0Bon*CaM*B - k0Boff*CaMB;
    rcn2B = k2Bon*Ca2CaM*B - k2Boff*Ca2CaMB;
    rcn4B = k4Bon*Ca4CaM*B - k4Boff*Ca4CaMB;

    Ca2CaN = CaNtot - Ca4CaN - CaMCa4CaN - Ca2CaMCa4CaN - Ca4CaMCa4CaN;
    rcnCa4CaN = kcanCaon*pow(Ca,2.0f)*Ca2CaN - kcanCaoff*Ca4CaN;
    rcn02CaN = k02can*pow(Ca,2.0f)*CaMCa4CaN - k20can*Ca2CaMCa4CaN;
    rcn24CaN = k24can*pow(Ca,2.0f)*Ca2CaMCa4CaN - k42can*Ca4CaMCa4CaN;
    rcn0CaN = kcanCaM0on*CaM*Ca4CaN - kcanCaM0off*CaMCa4CaN;
    rcn2CaN = kcanCaM2on*Ca2CaM*Ca4CaN - kcanCaM2off*Ca2CaMCa4CaN;
    rcn4CaN = kcanCaM4on*Ca4CaM*Ca4CaN - kcanCaM4off*Ca4CaMCa4CaN;

    Pix = 1.0f - Pb2 - Pb - Pt - Pt2 - Pa;
    rcnCKib2 = kib2*Ca2CaM*Pix - kb2i*Pb2;
    rcnCKb2b = kb24*pow(Ca,2.0f)*Pb2 - kb42*Pb;
    rcnCKib = kib*Ca4CaM*Pix - kbi*Pb;
    T = Pb + Pt + Pt2 + Pa;
    kbt = 0.055f*T + 0.0074f*pow(T,2.0f) + 0.015f*pow(T,3.0f);
    rcnCKbt = kbt*Pb - kpp1*PP1tot*Pt/(Kmpp1+CaMKIItot*Pt);
    rcnCKtt2 = kt42*Pt - kt24*pow(Ca,2.0f)*Pt2;
    rcnCKta = kta*Pt - kat*Ca4CaM*Pa;
    rcnCKt2a = kt2a*Pt2 - kat2*Ca2CaM*Pa;
    rcnCKt2b2 = kpp1*PP1tot*Pt2/(Kmpp1+CaMKIItot*Pt2);
    rcnCKai = kpp1*PP1tot*Pa/(Kmpp1+CaMKIItot*Pa);

    dCaM = 1e-3f*(-rcn02 - rcn0B - rcn0CaN);
    dCa2CaM = 1e-3f*(rcn02 - rcn24 - rcn2B - rcn2CaN + CaMKIItot*(-rcnCKib2 + rcnCKt2a));
    dCa4CaM = 1e-3f*(rcn24 - rcn4B - rcn4CaN + CaMKIItot*(-rcnCKib + rcnCKta));
    dCaMB = 1e-3f*(rcn0B-rcn02B);
    dCa2CaMB = 1e-3f*(rcn02B + rcn2B - rcn24B);
    dCa4CaMB = 1e-3f*(rcn24B + rcn4B);

