    dPb = 1e-3f*(rcnCKib + rcnCKb2b - rcnCKbt);
    dPt = 1e-3f*(rcnCKbt-rcnCKta-rcnCKtt2);
    dPt2 = 1e-3f*(rcnCKtt2-rcnCKt2a-rcnCKt2b2);
    dPa = 1e-3f*(rcnCKta+rcnCKt2a-rcnCKai);

    dCa4CaN = 1e-3f*(rcnCa4CaN - rcn0CaN - rcn2CaN - rcn4CaN);
    dCaMCa4CaN = 1e-3f*(rcn0CaN - rcn02CaN);
    dCa2CaMCa4CaN = 1e-3f*(rcn2CaN+rcn02CaN-rcn24CaN);
    dCa4CaMCa4CaN = 1e-3f*(rcn4CaN+rcn24CaN);

    d_finavalu[offset_1] = dCaM;
    d_finavalu[offset_2] = dCa2CaM;
    d_finavalu[offset_3] = dCa4CaM;
    d_finavalu[offset_4] = dCaMB;
    d_finavalu[offset_5] = dCa2CaMB;
    d_finavalu[offset_6] = dCa4CaMB;
    d_finavalu[offset_7] = dPb2;
    d_finavalu[offset_8] = dPb;
    d_finavalu[offset_9] = dPt;
    d_finavalu[offset_10] = dPt2;
    d_finavalu[offset_11] = dPa;
    d_finavalu[offset_12] = dCa4CaN;
    d_finavalu[offset_13] = dCaMCa4CaN;
    d_finavalu[offset_14] = dCa2CaMCa4CaN;
    d_finavalu[offset_15] = dCa4CaMCa4CaN;

    d_com[com_offset] = 1e-3f*(2.0f*CaMKIItot*(rcnCKtt2-rcnCKb2b) - 2.0f*(rcn02+rcn24+rcn02B+rcn24B+rcnCa4CaN+rcn02CaN+rcn24CaN));
}

