__kernel void solver_2(	int workload,
						int xmax,
						__global fp* x,
						__global fp* y,
						__global fp* params,
						__global fp* com,
						__global fp* err,
						__global fp* scale,
						__global fp* yy,
						__global fp* initvalu_temp,
						__global fp* finavalu_temp){

	int tid = (int)get_global_id(0);

	long y_pointer_initial;
	long y_pointer_current;
	long x_pointer_current;
	int err_pointer;
	int scale_pointer;
	int yy_pointer;
	int params_pointer;
	int initvalu_temp_pointer;
	int finavalu_temp_pointer;
	int com_pointer;

	fp err_exponent;
	fp h_init;
	fp h;
	fp tolerance;
	int xmin;

	int error;
	int outside;
	fp scale_min;
	fp scale_fina;

	int i, j, k;

	err_pointer = tid*EQUATIONS;
	scale_pointer = tid*EQUATIONS;
	yy_pointer = tid*EQUATIONS;
	params_pointer = tid*PARAMETERS;
	initvalu_temp_pointer = tid*EQUATIONS;
	finavalu_temp_pointer = tid*13*EQUATIONS;
	com_pointer = tid*3;

	err_exponent = 1.0 / 7.0;
	h_init = 1;
	h = h_init;
	xmin = 0;
	tolerance = 10 / (fp)(xmax - xmin);

	if (xmax < xmin || h <= 0.0){
		return;
	}
	if (xmax == xmin){
		return;
	}
	if (h > (xmax - xmin) ) {
		h = (fp)xmax - (fp)xmin;
	}

	if(tid<workload){

		for(k=1; k<(xmax+1); k++) {

			y_pointer_initial = ((long)tid)*((long)(xmax+1)*(long)EQUATIONS)+(long)(k-1)*(long)EQUATIONS;
			y_pointer_current = ((long)tid)*((long)(xmax+1)*(long)EQUATIONS)+(long)k*(long)EQUATIONS;
			x_pointer_current = ((long)tid)*(long)(xmax+1)+(long)k;

			x[x_pointer_current] = (fp)k;
			h = h_init;

			scale_fina = 1.0;

			for (j = 0; j < ATTEMPTS; j++) {

				error = 0;
				outside = 0;
				scale_min = MAX_SCALE_FACTOR;

				embedded_fehlberg_7_8_2_common(	h,
												x[x_pointer_current],
												&y[y_pointer_initial],
												&y[y_pointer_current],
												&params[params_pointer],
												&err[err_pointer],
												&initvalu_temp[initvalu_temp_pointer],
												&finavalu_temp[finavalu_temp_pointer],
												&com[com_pointer]);

				for(i=0; i<EQUATIONS; i++){
					if(err[err_pointer+i] > 0){
						error = 1;
					}
				}
				if (error != 1) {
					scale_fina = MAX_SCALE_FACTOR;
					break;
				}

				for(i=0; i<EQUATIONS; i++){
					if(y[y_pointer_initial+i] == 0.0){
						yy[yy_pointer+i] = tolerance;
					}
					else{
						yy[yy_pointer+i] = fabs(y[y_pointer_initial+i]);
					}
					scale[scale_pointer+i] = 0.8 * pow( tolerance * yy[yy_pointer+i] / err[err_pointer+i] , err_exponent );
					if(scale[scale_pointer+i]<scale_min){
						scale_min = scale[scale_pointer+i];
					}
				}
				scale_fina = minf( maxf(scale_min,MIN_SCALE_FACTOR), MAX_SCALE_FACTOR);

				for(i=0; i<EQUATIONS; i++){
					if ( err[err_pointer+i] > ( tolerance * yy[yy_pointer+i] ) ){
						outside = 1;
					}
				}
				if (outside == 0){
					break;
				}

				h = h * scale_fina;

				if (h >= 0.9) {
					h = 0.9;
				}

				if ( x[x_pointer_current] + h > (fp)xmax ){
					h = (fp)xmax - x[x_pointer_current];
				}
				else if ( x[x_pointer_current] + h + 0.5 * h > (fp)xmax ){
					h = 0.5 * h;
				}
			}

			x[x_pointer_current] = x[x_pointer_current] + h;

			if ( j >= ATTEMPTS ) {
				return;
			}
		}
	}

	return;
}

