inline double calcLikelihoodSum(__global const uchar *I, __global const int *ind, int numOnes, int index) {
    double likelihoodSum = 0.0;
    for (int x = 0; x < numOnes; x++) {
        int idx = ind[index * numOnes + x];
        double a = ((double)I[idx] - 100.0);
        double b = ((double)I[idx] - 228.0);
        likelihoodSum += (a * a - b * b) / 50.0;
    }
    return likelihoodSum;
}

inline void cdfCalc(__global double *CDF, __global const double *weights, int Nparticles) {
    CDF[0] = weights[0];
    for (int x = 1; x < Nparticles; x++) {
        CDF[x] = weights[x] + CDF[x - 1];
    }
}

inline double d_randu(__global int *seed, int index) {
    const int M = 2147483647;
    const int A = 1103515245;
    const int C = 12345;
    int num = A * seed[index] + C;
    seed[index] = num % M;
    return fabs((double)seed[index] / (double)M);
}

inline double d_randn(__global int *seed, int index) {
    double u = d_randu(seed, index);
    double v = d_randu(seed, index);
    double cosine = cos(2.0 * 3.14159265358979323846 * v);
    double rt = -2.0 * log(u);
    return sqrt(rt) * cosine;
}

inline int findIndexBin(__global const double *CDF, int beginIndex, int endIndex, double value) {
    if (endIndex < beginIndex)
        return -1;
    int middleIndex;
    while (endIndex > beginIndex) {
        middleIndex = beginIndex + ((endIndex - beginIndex) / 2);
        if (CDF[middleIndex] >= value) {
            if (middleIndex == 0)
                return middleIndex;
            else if (CDF[middleIndex - 1] < value)
                return middleIndex;
            else if (CDF[middleIndex - 1] == value) {
                while (middleIndex >= 0 && CDF[middleIndex] == value)
                    middleIndex--;
                middleIndex++;
                return middleIndex;
            }
        }
        if (CDF[middleIndex] > value)
            endIndex = middleIndex - 1;
        else
            beginIndex = middleIndex + 1;
    }
    return -1;
}

inline double dev_round_double(double value) {
    int newValue = (int)(value);
    if (value - newValue < 0.5f)
        return (double)newValue;
    else
        return (double)(newValue++);
}

__kernel void find_index_kernel(__global double *arrayX,
                                __global double *arrayY,
                                __global double *CDF,
                                __global double *u,
                                __global double *xj,
                                __global double *yj,
                                __global double *weights,
                                int Nparticles) {
    int i = (int)get_global_id(0);

    if (i < Nparticles) {
        int index = -1;
        for (int x = 0; x < Nparticles; x++) {
            if (CDF[x] >= u[i]) {
                index = x;
                break;
            }
        }
        if (index == -1) {
            index = Nparticles - 1;
        }

        xj[i] = arrayX[index];
        yj[i] = arrayY[index];
    }
}

__kernel void normalize_weights_kernel(__global double *weights,
                                       int Nparticles,
                                       __global double *partial_sums,
                                       __global double *CDF,
                                       __global double *u,
                                       __global int *seed) {
    int i = (int)get_global_id(0);

    if (i < Nparticles) {
        weights[i] = weights[i] / partial_sums[0];
    }

    barrier(CLK_GLOBAL_MEM_FENCE | CLK_LOCAL_MEM_FENCE);

    if (i == 0) {
        cdfCalc(CDF, weights, Nparticles);
        u[0] = (1.0 / ((double)Nparticles)) * d_randu(seed, i);
    }

    barrier(CLK_GLOBAL_MEM_FENCE | CLK_LOCAL_MEM_FENCE);

    if (i < Nparticles) {
        double u1 = u[0];
        u[i] = u1 + i / ((double)Nparticles);
    }
}

__kernel void sum_kernel(__global double *partial_sums, int Nparticles) {
    int i = (int)get_global_id(0);

    if (i == 0) {
        int num_blocks = (Nparticles + (int)get_local_size(0) - 1) / (int)get_local_size(0);
        double sum = 0.0;
        for (int x = 0; x < num_blocks; x++) {
            sum += partial_sums[x];
        }
        partial_sums[0] = sum;
    }
}

__kernel void likelihood_kernel(__global double *arrayX,
                                __global double *arrayY,
                                __global double *xj,
                                __global double *yj,
                                __global double *CDF,
                                __global int *ind,
                                __global int *objxy,
                                __global double *likelihood,
                                __global uchar *I,
                                __global double *u,
                                __global double *weights,
                                int Nparticles,
                                int countOnes,
                                int max_size,
                                int k,
                                int IszY,
                                int Nfr,
                                __global int *seed,
                                __global double *partial_sums,
                                __local double *buffer) {
    int i = (int)get_global_id(0);
    int lid = (int)get_local_id(0);

    if (i < Nparticles) {
        arrayX[i] = xj[i];
        arrayY[i] = yj[i];

        weights[i] = 1.0 / ((double)Nparticles);

        arrayX[i] = arrayX[i] + 1.0 + 5.0 * d_randn(seed, i);
        arrayY[i] = arrayY[i] - 2.0 + 2.0 * d_randn(seed, i);
    }

    barrier(CLK_GLOBAL_MEM_FENCE | CLK_LOCAL_MEM_FENCE);

    if (i < Nparticles) {
        for (int y = 0; y < countOnes; y++) {
            int indX = (int)dev_round_double(arrayX[i]) + objxy[y * 2 + 1];
            int indY = (int)dev_round_double(arrayY[i]) + objxy[y * 2];

            ind[i * countOnes + y] = abs(indX * IszY * Nfr + indY * Nfr + k);
            if (ind[i * countOnes + y] >= max_size)
                ind[i * countOnes + y] = 0;
        }
        likelihood[i] = calcLikelihoodSum(I, ind, countOnes, i);
        likelihood[i] = likelihood[i] / countOnes;
        weights[i] = weights[i] * exp(likelihood[i]);
    }

    buffer[lid] = 0.0;
    barrier(CLK_LOCAL_MEM_FENCE);

    if (i < Nparticles) {
        buffer[lid] = weights[i];
    }

    barrier(CLK_LOCAL_MEM_FENCE);

    for (uint s = get_local_size(0) / 2; s > 0; s >>= 1) {
        if ((uint)lid < s) {
            buffer[lid] += buffer[lid + s];
        }
        barrier(CLK_LOCAL_MEM_FENCE);
    }

    if (lid == 0) {
        partial_sums[get_group_id(0)] = buffer[0];
    }
}

