inline float d_dist_to_x(int p1,
                         int num,
                         int dim,
                         __global const float *coord_d,
                         __local const float *x_coord)
{
    float retval = 0.0f;
    for (int i = 0; i < dim; i++) {
        float tmp = coord_d[i * num + p1] - x_coord[i];
        retval += tmp * tmp;
    }
    return retval;
}

