                                 int dim,
                                 long x,
                                 int K)
{
    compute_cost_body(p, coord_d, work_mem_d, center_table_d,
                      switch_membership_d, x_coord, num, dim, x, K);
}

__kernel void kernel_compute_cost(__global const Point_Struct *p,
                                  __global const float *coord_d,
                                  __global float *work_mem_d,
                                  __global const int *center_table_d,
                                  __global char *switch_membership_d,
                                  __local float *x_coord,
                                  int num,
                                  int dim,
                                  long x,
                                  int K)
{
    compute_cost_body(p, coord_d, work_mem_d, center_table_d,
                      switch_membership_d, x_coord, num, dim, x, K);
}

typedef struct {
    float weight;
    long assign;
    float cost;
} Point_Struct;

inline float d_dist(const int p1,
                    const long p2,
                    const int num,
                    const int dim,
                    __global const float *coord_d)
{
    float retval = 0.0f;
    for (int i = 0; i < dim; i++) {
        float tmp = coord_d[i * num + p1] - coord_d[i * num + (int)p2];
        retval += tmp * tmp;
    }
    return retval;
}

__kernel void dummy_kernel(__global int *out)
{
    int gid = get_global_id(0);
    if (out != 0 && gid == 0) {
        out[0] = out[0];
    }
}

__kernel void kernel_compute_cost(__global const Point_Struct *p,
                                  __global const float *coord_d,
                                  __global float *work_mem_d,
                                  __global const int *center_table_d,
                                  __global char *switch_membership_d,
                                  __local float *unused_local,
                                  const int num,
                                  const int dim,
                                  const long x,
                                  const int K)
{
    (void)unused_local;

    int tid = get_global_id(0);
    if (tid < num) {
        int stride = K + 1;
        __global float *lower = work_mem_d + tid * stride;

        float x_cost = d_dist(tid, x, num, dim, coord_d) * p[tid].weight;

        if (x_cost < p[tid].cost) {
            switch_membership_d[tid] = '1';
            lower[K] += x_cost - p[tid].cost;
        } else {
            lower[center_table_d[(int)p[tid].assign]] += p[tid].cost - x_cost;
        }
    }
}
